{
  "shots": [
    {
      "shot_id": "SH10",
      "priority": "P0",
      "intent": "承接樱子关于银座的提问，让美咲以轻触袖口和一句承诺，把彩花的爱与痛分开，并明确带樱子离开旧日阴影。",
      "duration_sec": 5,
      "shot_type": "双人近景",
      "movement": "固定机位，保留列车行驶带来的极轻微稳定震动",
      "framing_focus": "首帧为行驶中的列车车厢内稳定双人近景：佐藤美咲三分之二侧脸位于画面中心偏左，嘴部清楚可见，右手轻放在佐藤樱子的校服袖口上；佐藤樱子侧脸位于画面右侧，眼线看向美咲，嘴唇闭合。",
      "action_intent": "本镜头只承担美咲一句回应与承诺：她保持手掌轻触樱子袖口，极轻地摇头后低声说出不会再回到旧日链条、要带樱子走向新生。",
      "emotion_intent": "美咲的保护欲从创伤里的紧绷转为温柔而坚定的引导，樱子以安静凝视承接这份承诺。",
      "scene_id": "EP22_TRAIN_CARRIAGE_MOVING",
      "scene_name": "行驶中的列车车厢",
      "dialogue": [
        {
          "speaker": "佐藤美咲",
          "text": "小樱，不会了。妈妈的爱，是真的，但藏着痛。我们走，远离开它。新生，从这里开始。",
          "purpose": "回答樱子上一镜关于银座是否还在的提问，把彩花的爱与痛分开，并给出离开银座、开始新生的承诺。",
          "source": "onscreen",
          "listener": "佐藤樱子"
        }
      ],
      "narration": [],
      "subtitle": [
        "小樱，不会了。",
        "妈妈的爱，是真的，但藏着痛。",
        "我们走，远离开它。新生，从这里开始。"
      ],
      "positive_core": "首帧是行驶中的列车车厢内稳定双人近景：佐藤美咲三分之二侧脸位于画面中心偏左，嘴部清楚可见，右手轻放在佐藤樱子的SAKURA_SCHOOL_UNIFORM_EP22袖口上；佐藤樱子侧脸位于画面右侧，眼线看向美咲，嘴唇闭合。竖屏9:16，低饱和写实电影感，车厢内暖白顶灯与窗外蓝紫、暖黄霓虹交替映在两人脸侧；佐藤美咲穿1套MISAKI_OLD_DRESS_EP22，佐藤樱子穿1套SAKURA_SCHOOL_UNIFORM_EP22，人物衣着完整，保持日常社交距离，朴素克制呈现。镜头过程中美咲只做极轻摇头和低声说话，樱子保持沉默闭嘴，目光停在美咲脸上。",
      "first_frame_contract": {
        "location": "行驶中的列车车厢",
        "visual_center": "佐藤美咲三分之二侧脸、清楚可见的嘴部，以及她轻放在佐藤樱子校服袖口上的右手",
        "visible_characters": [
          "佐藤美咲",
          "佐藤樱子"
        ],
        "character_positions": {
          "佐藤美咲": "画面中心偏左，坐在列车座位上，身体朝向樱子，三分之二侧脸面向镜头",
          "佐藤樱子": "画面右侧，坐在美咲身旁，侧脸面向美咲，双手自然靠近膝上"
        },
        "character_face_visibility": {
          "佐藤美咲": "脸部可见，三分之二侧脸；可见五官、眼神和嘴部，眼线温和落在樱子袖口与脸之间",
          "佐藤樱子": "脸部可见，正侧脸；可见五官和眼神，眼线看向美咲，嘴唇闭合"
        },
        "key_props": [
          "MISAKI_OLD_DRESS_EP22",
          "SAKURA_SCHOOL_UNIFORM_EP22"
        ],
        "speaking_state": "佐藤美咲是唯一主动说话人；佐藤樱子沉默闭嘴；不存在电话或远端声音",
        "camera_motion_allowed": "固定机位，允许列车行驶造成的极轻微环境震动"
      },
      "dialogue_blocking": {
        "active_speaker": "佐藤美咲",
        "first_speaker": "佐藤美咲",
        "speaker_visual_priority": "center_face",
        "silent_visible_characters": [
          "佐藤樱子"
        ],
        "lip_sync_policy": "single_active_speaker"
      },
      "i2v_contract": {
        "shot_task": "dialogue",
        "risk_level": "low",
        "risk_notes": "同一地点、单一主动说话人、两名可见角色首帧均露出脸部；动作仅限轻触袖口与极轻摇头，适合I2V稳定生成。",
        "prop_library": {
          "MISAKI_OLD_DRESS_EP22": {
            "display_name": "美咲旧礼服",
            "count": "1套",
            "size": "适配美咲身形，坐姿下裙摆至膝下",
            "color": "低饱和灰米色",
            "material": "丝质感布料",
            "structure": "细肩带旧礼服，外观朴素，人物衣着完整，保持日常社交距离呈现",
            "front_description": "不适用，非照片道具",
            "back_description": "不适用，非照片道具",
            "canonical_motion_policy": "作为服装随坐姿产生轻微布料褶皱；肩带可有极轻微偏斜，但整体保持得体稳定"
          },
          "SAKURA_SCHOOL_UNIFORM_EP22": {
            "display_name": "樱子校服",
            "count": "1套",
            "size": "适配中学生身形，裙摆至膝部附近",
            "color": "深蓝上衣、白色衬衫、深色裙摆",
            "material": "棉混纺制服布料",
            "structure": "日常校服套装，衣着完整，裙摆自然平整",
            "front_description": "不适用，非照片道具",
            "back_description": "不适用，非照片道具",
            "canonical_motion_policy": "随樱子坐姿和手部按压产生轻微褶皱；不脱离角色身体"
          }
        },
        "prop_contract": [
          {
            "prop_id": "MISAKI_OLD_DRESS_EP22",
            "position": "首帧穿在佐藤美咲身上，画面中心偏左可见胸肩至膝上区域的礼服布料",
            "first_frame_visible": true,
            "motion_policy": "仅随美咲坐姿、呼吸和极轻摇头产生细微布料褶皱，保持稳定",
            "controlled_by": "佐藤美咲",
            "current_visible_side": "none",
            "orientation_to_camera": "none",
            "quantity_policy": "仅1套，保持为美咲身上的同一套旧礼服，不新增副本",
            "flip_policy": "不适用，服装不翻面"
          },
          {
            "prop_id": "SAKURA_SCHOOL_UNIFORM_EP22",
            "position": "首帧穿在佐藤樱子身上，画面右侧可见深蓝上衣袖口与白色衬衫边缘，美咲右手轻放在袖口处",
            "first_frame_visible": true,
            "motion_policy": "随樱子安静坐姿产生轻微褶皱；袖口只承接美咲手掌的轻触，不安排拉扯或夸张摆动",
            "controlled_by": "佐藤樱子；袖口接触动作由佐藤美咲的右手完成",
            "current_visible_side": "none",
            "orientation_to_camera": "none",
            "quantity_policy": "仅1套，保持为樱子身上的同一套校服，不新增副本",
            "flip_policy": "不适用，服装不翻面"
          }
        ],
        "phone_contract": {
          "holder": "none",
          "screen_orientation": "none",
          "screen_content_visible": false
        }
      },
      "source_basis": "美咲的手掌轻触樱子的袖子；美咲摇头，声音柔软却坚定：小樱，不会了。妈妈的爱，是真的。但藏着痛。我们走，远离开它。新生，从这里开始。"
    }
  ],
  "qa_report": [
    {
      "check": "shots array length",
      "result": "pass",
      "notes": "仅输出SH10一个镜头，duration_sec为5。"
    },
    {
      "check": "I2V rule self-check",
      "result": "pass",
      "notes": "本镜头为dialogue任务，只有佐藤美咲一个onscreen主动说话人；佐藤樱子可见但沉默闭嘴，首帧两人脸部均可见。"
    },
    {
      "check": "continuity with SH09",
      "result": "pass",
      "notes": "延续行驶中的列车车厢、两人相邻坐姿和樱子上一镜提问后的状态；本镜头不重复樱子的提问，只呈现美咲回应。"
    },
    {
      "check": "prop consistency",
      "result": "pass",
      "notes": "沿用MISAKI_OLD_DRESS_EP22与SAKURA_SCHOOL_UNIFORM_EP22的数量、颜色、材质、结构和运动策略。"
    },
    {
      "check": "source traceability",
      "result": "pass",
      "notes": "镜头内容对应TARGET_FACTS index 13与TARGET_SPINE_ROW的美咲触袖口、摇头并承诺离开银座与开始新生。"
    }
  ]
}
